import React, { useState } from "react";
import "./BatchAnalysis.css";

function BatchAnalysis({ onFileChange, onAnalyze, loading, results, selectedFile }) {
  const [filters, setFilters] = useState({
    riskLevels: [],
    tenureRange: [0, 24],
    ordersRange: [0, 20]
  });

  const handleFileSelect = (e) => {
    if (e.target.files.length > 0) {
      onFileChange(e);
    }
  };

  const handleFilterChange = (key, value) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const SegmentCard = ({ data, riskLevel, color, icon, label }) => {
    const count = data.length;
    const avgChurn = data.reduce((sum, item) => sum + (item.Churn_Probability || 0), 0) / count * 100;
    const avgRecency = data.reduce((sum, item) => sum + (item.DaySinceLastOrder || 0), 0) / count;
    const avgOrders = data.reduce((sum, item) => sum + (item.OrderCount || 0), 0) / count;

    const getRecommendations = () => {
      if (riskLevel === 'High') {
        return [
          "Initiate executive-level 1:1 outreach immediately",
          "Offer premium, non-monetary incentives",
          "Analyze last 3 interactions to resolve root cause"
        ];
      } else if (riskLevel === 'Medium') {
        return [
          "Deploy exclusive discount within 7 days",
          "Focus on removing friction points",
          "Send personalized product recommendations"
        ];
      } else {
        return [
          "Enroll in tiered loyalty program",
          "Use non-sales content to maintain engagement",
          "Offer incentives for referrals"
        ];
      }
    };

    const downloadCSV = () => {
      const csv = convertToCSV(data);
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${riskLevel.toLowerCase()}_risk_customers.csv`;
      a.click();
      window.URL.revokeObjectURL(url);
    };

    return (
      <div className="segment-card">
        <div className="segment-header">
          <div className="segment-title" style={{ color }}>
            {icon} {label} ({count} Customers)
          </div>
          <span className="segment-priority">Priority: {riskLevel}</span>
        </div>
        
        <div className="segment-metrics">
          <div className="metric">
            <div className="metric-label">Avg. Churn Prob.</div>
            <div className="metric-value">{avgChurn.toFixed(1)}%</div>
          </div>
          <div className="metric">
            <div className="metric-label">Avg. Days Inactive</div>
            <div className="metric-value">{avgRecency.toFixed(1)} days</div>
          </div>
          <div className="metric">
            <div className="metric-label">Avg. Orders</div>
            <div className="metric-value">{avgOrders.toFixed(1)}</div>
          </div>
        </div>

        <div className="segment-recommendations">
          <div className="rec-title" style={{ color }}>
            {riskLevel === 'High' ? 'CRITICAL INTERVENTION' : 
             riskLevel === 'Medium' ? 'PROACTIVE ENGAGEMENT' : 'LOYALTY MAXIMIZATION'}
          </div>
          <ul>
            {getRecommendations().map((rec, index) => (
              <li key={index}>{rec}</li>
            ))}
          </ul>
        </div>

        <button className="download-btn" onClick={downloadCSV}>
          Download {riskLevel} Segment CSV
        </button>
      </div>
    );
  };

  const convertToCSV = (data) => {
    if (!data.length) return '';
    const headers = Object.keys(data[0]);
    const csv = [
      headers.join(','),
      ...data.map(row => headers.map(header => row[header]).join(','))
    ].join('\n');
    return csv;
  };

  const renderResults = () => {
    if (!results) return null;

    const totalRecords = results.summary?.total_customers || 0;
    const highRiskCount = results.summary?.high_risk_count || 0;
    const highRiskPercentage = results.summary?.high_risk_percentage || 0;
    const totalPotentialLoss = results.summary?.total_potential_loss || 0;

    const riskCategories = [
      { level: 'High', label: 'P1: High Risk (>70%)', color: '#ef4444', icon: '🚨' },
      { level: 'Medium', label: 'P2: Moderate Risk (31-70%)', color: '#f97316', icon: '⚠️' },
      { level: 'Low', label: 'P3: Low Risk (<=30%)', color: '#34d399', icon: '✅' }
    ];

    return (
      <div className="batch-results">
        <h3>📊 Batch Analysis Results</h3>
        
        {/* Executive Scorecard */}
        <div className="scorecard-section">
          <h4>⭐ Executive Scorecard</h4>
          <div className="scorecard-grid">
            <div className="scorecard-item">
              <div className="scorecard-value">{totalRecords.toLocaleString()}</div>
              <div className="scorecard-label">Total Customers</div>
            </div>
            <div className="scorecard-item">
              <div className="scorecard-value">{highRiskPercentage.toFixed(1)}%</div>
              <div className="scorecard-label">High-Risk %</div>
            </div>
            <div className="scorecard-item">
              <div className="scorecard-value">₹{(totalPotentialLoss / 100000).toFixed(1)}L</div>
              <div className="scorecard-label">Potential Loss</div>
            </div>
            <div className="scorecard-item">
              <div className="scorecard-value">{results.summary?.roi_retention?.toFixed(1)}x</div>
              <div className="scorecard-label">ROI Potential</div>
            </div>
          </div>
        </div>

        {/* Actionable Segmentation */}
        <div className="segmentation-section">
          <h4>💡 Actionable Segmentation</h4>
          <div className="segmentation-grid">
            {riskCategories.map(category => {
              const segmentData = results.data?.filter(item => 
                item.Risk_Level === category.label
              ) || [];
              return (
                <SegmentCard
                  key={category.level}
                  data={segmentData}
                  riskLevel={category.level}
                  color={category.color}
                  icon={category.icon}
                  label={category.label}
                />
              );
            })}
          </div>
        </div>

        {/* Download All */}
        <div className="download-all-section">
          <button 
            className="download-all-btn"
            onClick={() => {
              const csv = convertToCSV(results.data || []);
              const blob = new Blob([csv], { type: 'text/csv' });
              const url = window.URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url;
              a.download = 'churn_predictions_all.csv';
              a.click();
              window.URL.revokeObjectURL(url);
            }}
          >
            📥 Download All Filtered Results CSV
          </button>
        </div>
      </div>
    );
  };

  return (
    <div className="batch-analysis">
      <div className="batch-header">
        <h2>⚡ Bulk Customer Risk Assessment</h2>
        <p>Upload a CSV file containing multiple customer profiles for mass risk segmentation</p>
      </div>

      <div className="analysis-container">
        <div className="upload-section">
          <div className="file-upload-area">
            <input
              type="file"
              accept=".csv"
              onChange={handleFileSelect}
              className="file-input"
              id="batch-file"
            />
            <label htmlFor="batch-file" className="file-label">
              <span className="btn-icon">📎</span>
              Choose CSV File
            </label>
            
            {selectedFile && (
              <div className="file-info">
                <span className="file-success">✅</span>
                <div className="file-details">
                  <strong>{selectedFile.name}</strong>
                  <span>{(selectedFile.size / 1024).toFixed(1)} KB</span>
                </div>
              </div>
            )}
            
            <div className="file-requirements">
              <p>Required format: CSV with customer features matching individual analysis fields</p>
            </div>
          </div>

          <div className="action-buttons-bottom">
            <button 
              className="action-btn primary" 
              onClick={onAnalyze} 
              disabled={loading || !selectedFile}
            >
              {loading ? (
                <>
                  <div className="spinner"></div>
                  Processing Batch...
                </>
              ) : (
                <>
                  <span className="btn-icon">🚀</span>
                  Analyze Batch
                </>
              )}
            </button>
          </div>
        </div>

        {renderResults()}
      </div>
    </div>
  );
}

export default BatchAnalysis;
